class Node:
    def __init__(self, node_id, host):
        self.node_id = node_id
        self.host = host
        self.active = False

    def connect(self):
        self.active = True

    def __str__(self):
        return f"Node({self.node_id}) @ {self.host}"

class SecureNode(Node):
    def __init__(self, node_id, host, key):
        super().__init__(node_id, host)
        self.key = key

    def connect(self):
        print(f"Authenticating with key: {self.key}")
        super().connect()

n = Node(1, "192.168.0.1")
n.connect()
print(n)          # Node(1) @ 192.168.0.1
print(n.active)   # True

