import time

def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"{func.__name__} took {end - start:.4f}s")
        return result
    return wrapper

@timer
def compute(n):
    return sum(range(n))

compute(1000000)  # prints execution time

# Generator
def count_up(limit):
    n = 0
    while n < limit:
        yield n
        n += 1

for val in count_up(5):
    print(val)  # 0, 1, 2, 3, 4

# memory efficient — only one value exists at a time

